"use client";

import { useEffect, useRef, useState } from "react";
import { useChat } from "@/hooks/useChat";
import Modal from "@/components/ui/Modal";

export default function ChatHeader() {
  const [isModelModalOpen, setIsModelModalOpen] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const { resetChat } = useChat();
  const menuRef = useRef(null);

  useEffect(() => {
    if (!isMenuOpen) return;

    const handleOutsideClick = (event) => {
      if (menuRef.current && !menuRef.current.contains(event.target)) {
        setIsMenuOpen(false);
      }
    };

    document.addEventListener("mousedown", handleOutsideClick);
    return () => document.removeEventListener("mousedown", handleOutsideClick);
  }, [isMenuOpen]);

  const copyModelName = async () => {
    try {
      await navigator.clipboard.writeText("gemini-3-flash-preview");
    } catch {
      // ignore - clipboard may be blocked in some environments
    }
  };

  return (
    <>
      <div
        className="sticky top-0 z-50 
        backdrop-blur-xl 
        bg-white/60 dark:bg-black/40
        border-b border-gray-200/60 dark:border-gray-800
        shadow-sm"
      >
        <div className="h-16 flex items-center justify-between px-6 max-w-6xl mx-auto">
          {/* Left Section */}
          <div className="flex items-center gap-4">
            <div className="relative">
              <div
                className="w-9 h-9 rounded-xl 
                bg-gradient-to-br from-blue-500 via-purple-500 to-pink-500
                shadow-lg shadow-purple-500/20
                flex items-center justify-center
                text-white text-sm font-bold tracking-wide"
              >
                O
              </div>

              <div
                className="absolute inset-0 rounded-xl 
                bg-gradient-to-br from-blue-500 via-purple-500 to-pink-500
                blur-xl opacity-30 -z-10"
              />
            </div>

            <div className="flex flex-col leading-tight">
              <span className="text-base font-semibold 
                text-gray-900 dark:text-white tracking-tight"
              >
                OMNIX - AI
              </span>
              <span className="text-xs text-gray-500 dark:text-gray-400">
                Advanced Intelligence Model
              </span>
            </div>
          </div>

          {/* Right Section */}
          <div className="flex items-center gap-4">
            <div className="hidden sm:flex items-center gap-2 text-xs text-gray-500 dark:text-gray-400">
              <span className="relative flex h-2.5 w-2.5">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75" />
                <span className="relative inline-flex rounded-full h-2.5 w-2.5 bg-green-500" />
              </span>
              Online
            </div>

            <div className="relative" ref={menuRef}>
              <button
                onClick={() => setIsMenuOpen((prev) => !prev)}
                className="w-10 h-10 rounded-xl
                  bg-gray-100/70 dark:bg-gray-800/70
                  hover:bg-gray-200 dark:hover:bg-gray-700
                  transition-all duration-300
                  flex items-center justify-center
                  text-gray-600 dark:text-gray-300
                  hover:scale-105 active:scale-95
                  backdrop-blur-md"
              >
                <span className="text-lg">⋯</span>
              </button>

              {isMenuOpen && (
                <div className="absolute right-0 mt-2 w-48 rounded-2xl bg-white dark:bg-gray-950 shadow-lg ring-1 ring-black/10 border border-gray-200/60 dark:border-gray-800/60">
                  <button
                    onClick={() => {
                      resetChat();
                      setIsMenuOpen(false);
                    }}
                    className="w-full text-left px-4 py-3 text-sm text-gray-800 dark:text-gray-200 hover:bg-gray-100 dark:hover:bg-white/5 transition"
                  >
                    ➕ New chat
                  </button>
                  <button
                    onClick={() => {
                      setIsModelModalOpen(true);
                      setIsMenuOpen(false);
                    }}
                    className="w-full text-left px-4 py-3 text-sm text-gray-800 dark:text-gray-200 hover:bg-gray-100 dark:hover:bg-white/5 transition"
                  >
                    🧠 Model info
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="h-[1px] bg-gradient-to-r from-transparent via-gray-300/60 dark:via-gray-700 to-transparent" />
      </div>

      <Modal
        open={isModelModalOpen}
        onClose={() => setIsModelModalOpen(false)}
        title="Gemini 3 Flash Preview"
      >
        <div className="space-y-4 text-sm text-gray-700 dark:text-gray-200">
          <p>
            This chat is powered by Google’s <strong>Gemini 3 Flash Preview</strong> model.
            It provides fast, high-quality responses and is designed for broad conversational usage.
          </p>

          <div className="rounded-xl border border-gray-200/60 dark:border-gray-800/60 bg-gray-50 dark:bg-gray-900 p-4">
            <div className="flex items-start justify-between gap-3">
              <div>
                <p className="text-xs font-semibold uppercase tracking-wide text-gray-500 dark:text-gray-400">
                  Current model
                </p>
                <p className="mt-1 font-medium text-gray-900 dark:text-white">
                  gemini-3-flash-preview
                </p>
              </div>

              <button
                onClick={copyModelName}
                className="rounded-lg bg-white/70 dark:bg-white/10 px-3 py-2 text-xs font-medium text-gray-700 dark:text-gray-200 shadow-sm hover:bg-white dark:hover:bg-white/20 transition"
              >
                Copy
              </button>
            </div>
          </div>

          <p className="text-xs text-gray-500 dark:text-gray-400">
            Tip: Use the copy button to paste the model identifier into scripts,
            integrations, or prompts.
          </p>
        </div>
      </Modal>
    </>
  );
}
